import { ThemeProvider } from "./context/ThemeContext";
import Sidebar from "./components/Sidebar";
import TopBar from "./components/TopBar";
import ChatArea from "./components/ChatArea";

export default function App() {
    return (
        <ThemeProvider>
            <Sidebar />
            <main className="main">
                <TopBar />
                <ChatArea />
            </main>
        </ThemeProvider>
    );
}
